steps.cmd:
clear; clc; close all;
Kp=10; Ki=2; Kd=1;
tau=0.1; K_plant=1;   % plant: tau*dy/dt + y = K_plant*u
dt=0.001; t=0:dt:10;
r=ones(size(t)); y=zeros(size(t)); e_int=0; e_prev=0;

for k=2:length(t)
    e=r(k)-y(k-1);
    e_int=e_int+e*dt;
    de=(e-e_prev)/dt;
    u=Kp*e+Ki*e_int+Kd*de;
    y(k)=y(k-1)+dt*(-y(k-1)+K_plant*u)/tau;
    e_prev=e;
end

figure('Name','PID');
plot(t,r,'r--',t,y,'b-','LineWidth',2);
title('PID Step Response'); xlabel('Time (s)'); ylabel('Output');
legend('Reference','Output'); grid on;

rise_time = t(find(y >= 0.9, 1, 'first'));
settling_time = t(find(y >= 0.98, 1, 'first'));
overshoot = max(y) - 1;
fprintf('Rise Time: %.4f s
', rise_time);
fprintf('Settling Time: %.4f s
', settling_time);
fprintf('Overshoot: %.4f %%
', overshoot * 100);

figure('Name','Control Input');
plot(t, u, 'b-','LineWidth',2);
title('Control Input'); xlabel('Time (s)'); ylabel('Control Input'); grid on;

figure('Name','Error');
plot(t, r - y, 'b-','LineWidth',2);
title('Error'); xlabel('Time (s)'); ylabel('Error'); grid on;

load('pid_results.mat');
figure('Name','Loaded Results');
plot(t, y, 'b-','LineWidth',2);
title('Loaded Results'); xlabel('Time (s)'); ylabel('Output'); grid on;
